  useEffect(() => {
    if (!isLoading && user && (user as any)?.role !== "ADMIN") {
      navigate("/");
    }
  }, [user, isLoading, navigate]);

  if (isLoading) {
    return <p>Loading...</p>;
  }

  if ((user as any)?.role !== "ADMIN") {
    return (
      <main style={{ padding: "2rem", fontFamily: "sans-serif" }}>
        <h1 style={{ color: "#e74c3c" }}>Access Denied</h1>
        <p>You do not have permission to view this page.</p>
        <Link to="/">Go back to Main Page</Link>
      </main>
    );
  }

  return (
    <main style={{ padding: "2rem", fontFamily: "sans-serif" }}>
      <h1>Admin Panel</h1>
      <p>
        Welcome, <strong>{user?.identities?.username?.id}</strong>! You have
        admin access.
      </p>

      <div
        style={{
          marginTop: "1.5rem",
          padding: "1rem",
          background: "#f0f4ff",
          borderRadius: "8px",
          border: "1px solid #c0d0ff",
        }}
      >
        <h2>Admin Controls</h2>
        <p>Only users with the "ADMIN" role can see this section.</p>
      </div>

      <div style={{ marginTop: "1.5rem", display: "flex", gap: "1rem" }}>
        <Link to="/">
          <button
            style={{
              padding: "0.5rem 1rem",
              cursor: "pointer",
              background: "#3498db",
              color: "white",
              border: "none",
              borderRadius: "4px",
            }}
          >
            Back to Main Page
          </button>
        </Link>
        <button
          onClick={logout}
          style={{
            padding: "0.5rem 1rem",
            cursor: "pointer",
            background: "#e74c3c",
            color: "white",
            border: "none",
            borderRadius: "4px",
          }}
        >
          Logout
        </button>
      </div>
    </main>
  );
}

